import { type PackedKnot, toBytes, fromBytes } from './runtime/packed-knot';
import { MAGIC, writeHeader } from './lexicon';

/**
 * AtomicKnotSharder -- Atomizes a knot into self-contained shards.
 * Unlike standard slicing, every shard is a valid Lexicon-wrapped BLOB
 * that can be transported and reassembled without breaking headers.
 */
export class AtomicKnotSharder {
  /**
   * Shards a Uint8Array into N self-contained chunks.
   * Each chunk is tagged with its index and total count for reassembly.
   */
  static shard(data: Uint8Array, shardCount: number): Uint8Array[] {
    const shards: Uint8Array[] = [];
    const chunkSize = Math.ceil(data.length / shardCount);

    for (let i = 0; i < shardCount; i++) {
      const start = i * chunkSize;
      const end = Math.min(start + chunkSize, data.length);
      const payload = data.slice(start, end);

      // Meta: [index (4 bytes), total (4 bytes)]
      const meta = new Uint8Array(8);
      const view = new DataView(meta.buffer);
      view.setUint32(0, i, false);
      view.setUint32(4, shardCount, false);

      const atomicPayload = new Uint8Array(meta.length + payload.length);
      atomicPayload.set(meta, 0);
      atomicPayload.set(payload, meta.length);

      // Wrap each shard as a BLOB so it's structurally valid in the dark sector
      const buffer = new Uint8Array(8 + atomicPayload.length);
      writeHeader(buffer, MAGIC.BLOB, atomicPayload.length);
      buffer.set(atomicPayload, 8);
      
      shards.push(buffer);
    }

    return shards;
  }

  /**
   * Reassembles shards into the original Uint8Array.
   */
  static reassemble(shards: Uint8Array[]): Uint8Array {
    const parts: { index: number; data: Uint8Array }[] = [];
    
    for (const shard of shards) {
      const view = new DataView(shard.buffer, shard.byteOffset, shard.byteLength);
      const index = view.getUint32(8, false);
      const data = shard.slice(16);
      parts.push({ index, data });
    }

    parts.sort((a, b) => a.index - b.index);
    
    const totalLen = parts.reduce((sum, p) => sum + p.data.length, 0);
    const combined = new Uint8Array(totalLen);
    let offset = 0;
    for (const p of parts) {
      combined.set(p.data, offset);
      offset += p.data.length;
    }

    return combined;
  }
}
